--
-- Table structure for table `osg_position`
--

DROP TABLE IF EXISTS `osg_position`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `osg_position` (
  `position_id` bigint NOT NULL AUTO_INCREMENT COMMENT '岗位ID',
  `position_category` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `industry` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '行业分类(Investment Bank/Consulting/Tech/PE/VC/Other)',
  `company_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '公司名称',
  `company_type` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '公司类别',
  `company_website` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '公司官网',
  `position_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '岗位名称',
  `department` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '部门',
  `region` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recruitment_cycle` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '招聘周期(可多值逗号分隔)',
  `project_year` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '项目时间/年份',
  `publish_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '发布时间',
  `deadline` datetime DEFAULT NULL COMMENT '截止时间',
  `deadline_text` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '截止时间文本描述(如Rolling ASAP)',
  `display_status` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'visible' COMMENT '展示状态(visible/hidden/expired)',
  `display_start_time` datetime NOT NULL COMMENT '展示开始时间',
  `display_end_time` datetime NOT NULL COMMENT '展示结束时间',
  `position_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '岗位链接',
  `application_note` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '投递备注',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`position_id`),
  UNIQUE KEY `uk_osg_position_dedup` (`company_name`,`position_name`,`position_category`,`region`,`city`,`project_year`),
  KEY `idx_osg_position_industry` (`industry`),
  KEY `idx_osg_position_company` (`company_name`),
  KEY `idx_osg_position_status` (`display_status`),
  KEY `idx_osg_position_publish_time` (`publish_time`),
  KEY `idx_osg_position_cycle` (`recruitment_cycle`)
) ENGINE=InnoDB AUTO_INCREMENT=307 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='OSG岗位信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `osg_position`
--

LOCK TABLES `osg_position` WRITE;
/*!40000 ALTER TABLE `osg_position` DISABLE KEYS */;
